--
-- Name: machine_group_member_ids(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.machine_group_member_ids(target_id character varying) RETURNS TABLE(id character varying)
    LANGUAGE sql STABLE
    AS $$
    WITH host AS (
        SELECT COALESCE(
            (SELECT mi.machine_id
             FROM machine_interfaces mi
             WHERE mi.attached_dpu_machine_id = target_id
               AND mi.machine_id != mi.attached_dpu_machine_id
             LIMIT 1),
            target_id
        ) AS id
    )
    SELECT id FROM host
    UNION
    SELECT mi.attached_dpu_machine_id
    FROM machine_interfaces mi
    JOIN host ON mi.machine_id = host.id
    WHERE mi.attached_dpu_machine_id IS NOT NULL
      AND mi.machine_id != mi.attached_dpu_machine_id;
$$;


