    attached_dpu_machine_id character varying(64),
    machine_id character varying(64),
    segment_id uuid NOT NULL,
    mac_address macaddr NOT NULL,
    domain_id uuid,
    primary_interface boolean NOT NULL,
    hostname character varying(63) NOT NULL,
    created timestamp with time zone DEFAULT now() NOT NULL,
    last_dhcp timestamp with time zone,
    switch_id character varying(64),
    power_shelf_id character varying(64),
    association_type public.association_type DEFAULT 'None'::public.association_type NOT NULL,
    interface_type public.interface_type DEFAULT 'Data'::public.interface_type NOT NULL,
    boot_interface_id text,
    CONSTRAINT chk_max_one_association CHECK ((((association_type = 'None'::public.association_type) AND (machine_id IS NULL) AND (power_shelf_id IS NULL) AND (switch_id IS NULL)) OR ((association_type <> 'None'::public.association_type) AND (num_nonnulls(machine_id, power_shelf_id, switch_id) <= 1))))
);


--
-- Name: dns_records_adm_combined; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.dns_records_adm_combined AS
 SELECT concat(mi.machine_id, '.adm.', d.name, '.') AS q_name,
    mia.address AS resource_record,
    (COALESCE(rt.type_name, (
        CASE
            WHEN (family(mia.address) = 6) THEN 'AAAA'::text
            ELSE 'A'::text
        END)::character varying))::character varying(10) AS q_type,
    meta.ttl,
    d.id AS domain_id
   FROM ((((public.machine_interfaces mi
     JOIN public.machine_interface_addresses mia ON ((mia.interface_id = mi.id)))
     JOIN public.domains d ON (((d.id = mi.domain_id) AND (mi.primary_interface = true))))
     LEFT JOIN public.dns_record_metadata meta ON ((meta.id = mi.id)))
     LEFT JOIN public.dns_record_types rt ON ((meta.record_type_id = rt.id)))
  WHERE (mi.machine_id IS NOT NULL);


--
-- Name: dns_records_bmc_dpu_id; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.dns_records_bmc_dpu_id AS
 SELECT concat(mi.machine_id, '.bmc.', d.name, '.') AS q_name,
    mia.address AS resource_record,
    (COALESCE(rt.type_name, (
        CASE
            WHEN (family(mia.address) = 6) THEN 'AAAA'::text
            ELSE 'A'::text
        END)::character varying))::character varying(10) AS q_type,
    meta.ttl,
    d.id AS domain_id
   FROM ((((public.machine_interfaces mi
     JOIN public.machine_interface_addresses mia ON ((mia.interface_id = mi.id)))
     JOIN public.domains d ON ((d.id = mi.domain_id)))
     LEFT JOIN public.dns_record_metadata meta ON ((meta.id = mi.id)))
     LEFT JOIN public.dns_record_types rt ON ((meta.record_type_id = rt.id)))
  WHERE ((mi.machine_id IS NOT NULL) AND (mi.interface_type = 'Bmc'::public.interface_type) AND starts_with((mi.machine_id)::text, 'fm100d'::text));


--
-- Name: dns_records_bmc_host_id; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.dns_records_bmc_host_id AS
 SELECT concat(mi.machine_id, '.bmc.', d.name, '.') AS q_name,
    mia.address AS resource_record,
    (COALESCE(rt.type_name, (
        CASE
            WHEN (family(mia.address) = 6) THEN 'AAAA'::text
            ELSE 'A'::text
        END)::character varying))::character varying(10) AS q_type,
    meta.ttl,
    d.id AS domain_id
   FROM ((((public.machine_interfaces mi
     JOIN public.machine_interface_addresses mia ON ((mia.interface_id = mi.id)))
     JOIN public.domains d ON ((d.id = mi.domain_id)))
     LEFT JOIN public.dns_record_metadata meta ON ((meta.id = mi.id)))
     LEFT JOIN public.dns_record_types rt ON ((meta.record_type_id = rt.id)))
  WHERE ((mi.machine_id IS NOT NULL) AND (mi.interface_type = 'Bmc'::public.interface_type) AND (starts_with((mi.machine_id)::text, 'fm100h'::text) OR starts_with((mi.machine_id)::text, 'fm100p'::text)));


