--
-- Name: network_segments; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.network_segments (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    name character varying NOT NULL,
    subdomain_id uuid,
    vpc_id uuid,
    mtu integer DEFAULT 1500 NOT NULL,
    version character varying(64) NOT NULL,
    created timestamp with time zone DEFAULT now() NOT NULL,
    updated timestamp with time zone DEFAULT now() NOT NULL,
    deleted timestamp with time zone,
    vni_id integer,
    controller_state_version character varying(64) DEFAULT 'V1-T1666644937952268'::character varying NOT NULL,
    controller_state jsonb DEFAULT '{"state": "provisioning"}'::jsonb NOT NULL,
    vlan_id smallint,
    network_segment_type public.network_segment_type_t DEFAULT 'tenant'::public.network_segment_type_t NOT NULL,
    controller_state_outcome jsonb,
    can_stretch boolean,
    allocation_strategy text DEFAULT 'dynamic'::text NOT NULL,
    CONSTRAINT network_segments_mtu_check CHECK (((mtu >= 576) AND (mtu <= 9000))),
    CONSTRAINT network_segments_vlan_id_check CHECK (((0 <= vlan_id) AND (vlan_id < 4096)))
);


--
-- Name: dns_records_instance; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.dns_records_instance AS
 SELECT concat(ia.hostname, '.', d.name, '.') AS q_name,
    ia.address AS resource_record,
    (
        CASE
            WHEN (family(ia.address) = 6) THEN 'AAAA'::text
            ELSE 'A'::text
        END)::character varying(10) AS q_type,
    NULL::integer AS ttl,
    d.id AS domain_id
   FROM ((public.instance_addresses ia
     JOIN public.network_segments ns ON ((ns.id = ia.segment_id)))
     JOIN public.domains d ON ((d.id = ns.subdomain_id)))
  WHERE ((ia.hostname IS NOT NULL) AND (ns.network_segment_type <> 'host_inband'::public.network_segment_type_t));


--
-- Name: dns_records_shortname_combined; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.dns_records_shortname_combined AS
 SELECT concat(mi.hostname, '.', d.name, '.') AS q_name,
    mia.address AS resource_record,
    (COALESCE(rt.type_name, (
        CASE
            WHEN (family(mia.address) = 6) THEN 'AAAA'::text
            ELSE 'A'::text
        END)::character varying))::character varying(10) AS q_type,
    meta.ttl,
    d.id AS domain_id
   FROM ((((public.machine_interfaces mi
     JOIN public.machine_interface_addresses mia ON ((mia.interface_id = mi.id)))
     JOIN public.domains d ON ((d.id = mi.domain_id)))
     LEFT JOIN public.dns_record_metadata meta ON ((meta.id = mi.id)))
     LEFT JOIN public.dns_record_types rt ON ((meta.record_type_id = rt.id)))
  WHERE ((mi.primary_interface = true) OR (mi.interface_type = 'Bmc'::public.interface_type));


--
-- Name: dns_records; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.dns_records AS
 SELECT q_name,
    resource_record,
    q_type,
    ttl,
    domain_id
   FROM ((((public.dns_records_shortname_combined
     FULL JOIN public.dns_records_adm_combined USING (q_name, resource_record, q_type, ttl, domain_id))
     FULL JOIN public.dns_records_bmc_host_id USING (q_name, resource_record, q_type, ttl, domain_id))
     FULL JOIN public.dns_records_bmc_dpu_id USING (q_name, resource_record, q_type, ttl, domain_id))
     FULL JOIN public.dns_records_instance USING (q_name, resource_record, q_type, ttl, domain_id));


--
-- Name: dns_records_machines; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.dns_records_machines AS
 SELECT q_name,
    resource_record
   FROM (((public.dns_records_shortname_combined
     FULL JOIN public.dns_records_adm_combined USING (q_name, resource_record))
     FULL JOIN public.dns_records_bmc_host_id USING (q_name, resource_record))
     FULL JOIN public.dns_records_bmc_dpu_id USING (q_name, resource_record));


